@ARTICLE{10.1139/apnm-2025-0344,
	author = {Sakar M(1), Doğan Ç(2), Apaydın N(1), İpekoğlu G(1).},
	title = {Does the MC4R rs17782313 gene polymorphism affect the rate of exercise-induced fat oxidation?},
	journal = {Appl Physiol Nutr Metab},
	year = {2026},
	abstract = {This study investigated the effect of the MC4R rs17782313 (T > C) polymorphism on substrate oxidation and metabolic responses during exercise in healthy sedentary men. Forty-eight participants (aged 20-30 years) underwent genotyping and completed a graded exercise test with respiratory gas analysis to assess oxygen consumption (VO2), respiratory quotient (RQ), and fat and carbohydrate oxidation rates. Participants were grouped as C-allele carriers (risk allele) and TT homozygotes. Group comparisons were conducted for VO2, RQ, substrate oxidation rates, and body mass index (BMI). Statistical analysis revealed no significant differences between genotypes in RQ, fat oxidation percentage, or carbohydrate oxidation percentage during moderate-intensity exercise (p > 0.05). However, significant differences were observed in BMI, with C-allele carriers exhibiting higher BMI values compared to TT homozygotes (p < 0.05). These results indicate that while the MC4R rs17782313 variant is associated with increased adiposity, it does not appear to affect acute substrate utilization during exercise. Thus, its contribution to obesity risk may be primarily mediated by behavioral and neuroendocrine mechanisms influencing energy intake rather than impairments in metabolic flexibility.},
	doi = {10.1139/apnm-2025-0344},
	pmid = {41429006 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molmet.2025.102305,
	author = {Grothen JER(1) and Martinez JM(2) and Sidiropoulos N(2) and Massier L(3) and Zareifi D(4) and Zhong J(4) and Davidsen I(2) and Platou JW(2) and Mandelbaum J(2) and Rothe P(2) and Hvid H(2), Grønborg M(2) and Madsen CT(2) and Bruun JM(5), Rydén M(6) and Mejhert N(6) and Helge JW(7) and Gerhart-Hines Z(8) and Pedersen TÅ(9).},
	title = {Single cell transcriptomics of human weight loss links adipocyte NPY1R to control of lipolysis.},
	abstract = {BACKGROUND: Combination of increased physical exercise and hypocaloric diet has long been recognized to improve cardiometabolic health and adipose tissue function, including lipid turnover. How such lifestyle interventions mediate benefits at the cellular level remains unknown. Given the critical role of subcutaneous white adipose tissue (scWAT) to systemic metabolic homeostasis, we set out to interrogate how exercise and diet lifestyle intervention impacted scWAT in individuals living with obesity, with a particular focus on lipolytic capacity and cell-specific gene profiling. METHODS: Single nuclei RNA sequencing (snRNAseq) was performed on cryopreserved scWAT biopsies originally collected before and after lifestyle intervention, involving regular exercise and hypocaloric diet in obese individuals. Findings on regulation of lipolysis in adipocytes were followed up with meta-analysis of clinical studies and pharmacological experiments in mature human adipocytes. RESULTS: snRNAseq analysis revealed intervention-induced changes in all scWAT cell-types. In adipocytes genes linked to protein and organelle turnover, branch chain amino acid catabolism, and lipolytic control were most significantly regulated. We identified a cell autonomous brake on adipocyte lipolysis via the neuropeptide Y receptor 1 (NPY1R). Expression of adipocyte NPY1R was reduced after weight loss and correlated positively with body fat percentage and body mass index. Findings were confirmed in meta-analysis across 23 studies. Finally, we found a negative correlation between NPY1R and beta-adrenergic-induced lipolysis and that NPY dose-dependently attenuated lipolysis and cAMP-signaling in primary human subcutaneous adipocytes. CONCLUSIONS: Our work suggests that decreases in adipocyte NPY1R during weight loss boost lipolytic capacity and contribute to improved systemic cardiometabolic health.},
	doi = {10.1016/j.molmet.2025.102305},
	pmid = {41412283 [Indexed for MEDLINE]},
	note = {PMC12926987}
}

